import React, { useState } from "react";
import { motion } from "framer-motion";
import Layout from "../components/layout/Layout";

const INTERESTS = [
  "BC Implementation",
  "ERP Consulting",
  "Custom Development",
  "API Integrations",
  "ERP Modernisation",
  "Support Retainer",
  "Sales App",
  "SRM Platform",
  "Executive Dashboard",
];

const TIMEZONES = [
  "IST (India)",
  "GST (UAE)",
  "GMT (UK)",
  "SGT (Singapore)",
  "EST (USA)",
  "Other",
];

const INFO = [
  {
    icon: "📧",
    label: "Email",
    value: "[projects@velvotix.com](mailto:projects@velvotix.com)",
    color: "#0099FF",
  },
  {
    icon: "🌍",
    label: "Regions",
    value: "India · UAE · UK · SG · USA",
    color: "#FF7A00",
  },
  {
    icon: "⏱",
    label: "Response",
    value: "Within 24 hours guaranteed",
    color: "#00D9FF",
  },
  {
    icon: "📍",
    label: "Based in",
    value: "India, remote-first globally",
    color: "#FF5500",
  },
];

const encode = (data) =>
  Object.keys(data)
    .map((key) => encodeURIComponent(key) + "=" + encodeURIComponent(data[key]))
    .join("&");

export default function ContactPage() {
  const [done, setDone] = useState(false);

  const [form, setForm] = useState({
    name: "",
    email: "",
    company: "",
    region: "",
    timezone: "",
    interest: [],
    message: "",
  });

  const toggle = (item) =>
    setForm((f) => ({
      ...f,
      interest: f.interest.includes(item)
        ? f.interest.filter((x) => x !== item)
        : [...f.interest, item],
    }));

  const handleSubmit = async (e) => {
    e.preventDefault();

