              initial={{ opacity: 0, x: -18 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: 0.15 }}
              style={{
                display: "flex",
                flexDirection: "column",
                gap: 14,
              }}
            >
              {INFO.map((item) => (
                <div
                  key={item.label}
                  className="card"
                  style={{
                    padding: 18,
                    display: "flex",
                    gap: 14,
                  }}
                >
                  <div
                    style={{
                      width: 40,
                      height: 40,
                      borderRadius: 12,
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      fontSize: 18,
                      background: `${item.color}14`,
                    }}
                  >
                    {item.icon}
                  </div>

                  <div>
                    <div
                      style={{
                        fontSize: 11,
                        fontWeight: 600,
                        color: "var(--text3)",
                        marginBottom: 3,
                      }}
                    >
                      {item.label}
                    </div>

                    <div
                      style={{
                        fontSize: 13.5,
                        fontWeight: 500,
                        color: "var(--text)",
                      }}
                    >
                      {item.value}
                    </div>
                  </div>
                </div>
              ))}
            </motion.div>

            {/* Form */}
            <motion.div
              initial={{ opacity: 0, x: 18 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ delay: 0.2 }}
            >
              {done ? (
                <motion.div
                  initial={{
                    opacity: 0,
                    scale: 0.93,
                  }}
                  animate={{
                    opacity: 1,
                    scale: 1,
                  }}
                  className="card"
                  style={{
                    padding: "52px 24px",
                    textAlign: "center",
                  }}
                >
                  <div
                    style={{
                      fontSize: 44,
                      marginBottom: 14,
                    }}
                  >
                    ✅
                  </div>

                  <h3
                    className="f-display"
                    style={{
                      fontSize: "1.4rem",
                      fontWeight: 700,
                    }}
                  >
                    Message Received
                  </h3>

                  <p
                    style={{
                      color: "var(--text2)",
                    }}
                  >
                    Our team will be in touch within 24 hours.
                  </p>
                </motion.div>
              ) : (
                <form
                  name="contact"
                  method="POST"
                  data-netlify="true"
                  data-netlify-honeypot="bot-field"
                  onSubmit={handleSubmit}
                  className="card"
                  style={{
                    padding: "clamp(18px,4vw,30px)",
                    display: "flex",
                    flexDirection: "column",
                    gap: 20,
                  }}
                >
                  <input type="hidden" name="form-name" value="contact" />

                  <input type="hidden" name="bot-field" />

                  <div
                    style={{
                      display: "grid",
                      gridTemplateColumns: "1fr",
                      gap: 16,
                    }}
                  >
                    <div>
                      <label style={lbl}>Full Name</label>
                      <input
                        name="name"
                        className="inp"
                        required
                        value={form.name}
                        onChange={(e) =>
                          setForm((s) => ({
                            ...s,
                            name: e.target.value,
                          }))
                        }
                      />
                    </div>

                    <div>
                      <label style={lbl}>Work Email</label>
                      <input
                        name="email"
                        type="email"
                        className="inp"
                        required
                        value={form.email}
                        onChange={(e) =>
                          setForm((s) => ({
                            ...s,
                            email: e.target.value,
                          }))
                        }
                      />
                    </div>

                    <div>
                      <label style={lbl}>Company</label>
                      <input
                        name="company"
                        className="inp"
                        required
                        value={form.company}
                        onChange={(e) =>
                          setForm((s) => ({
                            ...s,
                            company: e.target.value,
                          }))
                        }
                      />
                    </div>

                    <div>
                      <label style={lbl}>Your Country</label>
                      <input
                        name="region"
                        className="inp"
                        required
                        value={form.region}
                        onChange={(e) =>
                          setForm((s) => ({
                            ...s,
                            region: e.target.value,
                          }))
                        }
                      />
                    </div>
                  </div>

                  <div>
                    <label style={lbl}>Your Timezone</label>

                    <div
                      style={{
                        display: "flex",
                        flexWrap: "wrap",
                        gap: 8,
                      }}
                    >
                      {TIMEZONES.map((tz) => (
                        <button
                          key={tz}
                          type="button"
                          onClick={() =>
                            setForm((f) => ({
                              ...f,
                              timezone: tz,
                            }))
                          }
                        >
                          {tz}
                        </button>
                      ))}
                    </div>

                    <input
                      type="hidden"
                      name="timezone"
                      value={form.timezone}
                    />
                  </div>

                  <div>
                    <label style={lbl}>Interests</label>

                    <div
                      style={{
                        display: "flex",
                        flexWrap: "wrap",
                        gap: 8,
                      }}
                    >
                      {INTERESTS.map((item) => (
                        <button
                          key={item}
                          type="button"
                          onClick={() => toggle(item)}
                        >
                          {item}
                        </button>
                      ))}
                    </div>

                    <input
                      type="hidden"
                      name="interest"
                      value={form.interest.join(", ")}
                    />
                  </div>

                  <div>
                    <label style={lbl}>Tell us about your challenge</label>

                    <textarea
                      name="message"
                      className="inp"
                      rows={4}
                      value={form.message}
                      onChange={(e) =>
                        setForm((f) => ({
                          ...f,
                          message: e.target.value,
                        }))
                      }
                    />
                  </div>

                  <button
                    type="submit"
                    className="btn btn-blue btn-lg"
                    style={{ width: "100%" }}
                  >
                    Send Message
                  </button>
                </form>
              )}
            </motion.div>
          </div>
        </div>
      </section>
    </Layout>
  );
}
